DROP TABLE IF EXISTS person_relations;
DROP TABLE IF EXISTS people;
DROP TABLE IF EXISTS thread_passages;
DROP TABLE IF EXISTS editorial_threads;
DROP TABLE IF EXISTS chunk_external_references;
